const file = $.steps.downloadFile.response || {};
const name = file.name || file.title || 'Unknown';
const mimeType = file.mimeType || 'unknown';
const size = file.size || 0;
const modifiedTime = file.modifiedTime || file.modifiedDate || '';
const content = file.content || file.body || '';

return {
  name,
  mimeType,
  size,
  modifiedTime,
  contentPreview: typeof content === 'string' ? content.slice(0, 4000) : JSON.stringify(content).slice(0, 4000),
  hasContent: content.length > 0
};

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { summary: raw, keyPoints: [] }; }

const ai = $.steps.parseAI.output;
const info = $.steps.extractFileInfo.output;
const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Google Drive File Summary', emoji: true } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*File:*\n' + info.name },
  { type: 'mrkdwn', text: '*Type:*\n' + (ai.fileType || info.mimeType) }
] });
blocks.push({ type: 'divider' });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Summary:*\n' + (ai.summary || 'No summary available') } });
if (ai.keyPoints && ai.keyPoints.length > 0) {
  let kpText = '*Key Points:*\n';
  ai.keyPoints.forEach(kp => { kpText += '- ' + kp + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: kpText } });
}
if (ai.actionItems && ai.actionItems.length > 0) {
  let aiText = '*Action Items:*\n';
  ai.actionItems.forEach(item => { aiText += '- ' + item + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: aiText } });
}
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'File: ' + info.name + ' | Modified: ' + info.modifiedTime }] });
const fallback = 'File summary: ' + info.name + ' - ' + (ai.summary || '').slice(0, 150);
return { blocks, fallback };
